class RedisSession(CallbackDict, SessionMixin):
    def __init__(self, initial=None, sid=None, new=False):
        def on_update(self):
            self.modified = True
        CallbackDict.__init__(self, initial, on_update)
        self.sid = sid
        self.new = new
        self.modified = False


class RedisSessionInterface(SessionInterface):
    serializer = pickle
    session_class = RedisSession

    def __init__(self, redis_client, prefix='session:'):
        self.redis = redis_client
        self.prefix = prefix

    def generate_sid(self):
        return str(uuid.uuid4())

    def get_redis_expiration_time(self, app, session):
        if session.permanent:
            return app.permanent_session_lifetime
        return timedelta(days=1)

    def open_session(self, app, request):
        sid = request.cookies.get(app.session_cookie_name)
        if not sid:
            sid = self.generate_sid()
            return self.session_class(sid=sid, new=True)
        
        val = self.redis.get(self.prefix + sid)
        if val is not None:
            try:
                data = self.serializer.loads(val)
                return self.session_class(data, sid=sid)
            except:
                return self.session_class(sid=sid, new=True)
        return self.session_class(sid=sid, new=True)

    def save_session(self, app, session, response):
        domain = self.get_cookie_domain(app)
        path = self.get_cookie_path(app)
        
        if not session:
            if session.modified:
                self.redis.delete(self.prefix + session.sid)
                response.delete_cookie(app.session_cookie_name, domain=domain, path=path)
            return

        redis_exp = self.get_redis_expiration_time(app, session)
        cookie_exp = self.get_expiration_time(app, session)
        val = self.serializer.dumps(dict(session))
        
        self.redis.setex(
            self.prefix + session.sid,
            int(redis_exp.total_seconds()),
            val
        )
        
        response.set_cookie(
            app.session_cookie_name,
            session.sid,
            expires=cookie_exp,
            httponly=True,
            domain=domain,
            path=path,
            secure=False
        )


app.session_interface = RedisSessionInterface(redis_client)


def cache_query(expiration=300, key_prefix='query'):
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            cache_key_parts = [key_prefix, func.__name__]
            
            if args:
                args_str = '_'.join(str(arg) for arg in args)
                cache_key_parts.append(args_str)
            
            if kwargs:
                kwargs_str = '_'.join(f"{k}:{v}" for k, v in sorted(kwargs.items()))
                cache_key_parts.append(kwargs_str)
            
            cache_key = ':'.join(cache_key_parts)
            cache_key_hash = hashlib.md5(cache_key.encode()).hexdigest()
            final_cache_key = f"{key_prefix}:{cache_key_hash}"
            
            cached_result = redis_cache_client.get(final_cache_key)
            if cached_result is not None:
                try:
                    return json.loads(cached_result)
                except:
                    pass
            
            result = func(*args, **kwargs)
            
            try:
                redis_cache_client.setex(
                    final_cache_key,
                    expiration,
                    json.dumps(result)
                )
            except (TypeError, ValueError):
                pass
            
            return result
        return wrapper
    return decorator


def invalidate_cache(key_prefix='query', pattern=None):
    if pattern:
        keys = redis_cache_client.keys(f"{key_prefix}:{pattern}")
    else:
        keys = redis_cache_client.keys(f"{key_prefix}:*")
    
    if keys:
        redis_cache_client.delete(*keys)


@cache_query(expiration=600, key_prefix='user')
def get_user_from_db(user_id):
    import time
    time.sleep(0.5)
    return {
        'id': user_id,
        'name': f'User {user_id}',
        'email': f'user{user_id}@example.com',
        'role': 'admin' if user_id == 1 else 'user'
    }


@cache_query(expiration=300, key_prefix='products')
def get_products_from_db(category=None, limit=10):
    import time
    time.sleep(0.3)
    products = [
        {'id': i, 'name': f'Product {i}', 'category': category or 'general', 'price': i * 10}
        for i in range(1, limit + 1)
    ]
    return products


