@app.route('/login', methods=['POST'])
def login():
    data = request.get_json() or {}
    username = data.get('username', 'guest')
    
    session['username'] = username
    session['user_id'] = abs(hash(username)) % 1000
    session['logged_in'] = True
    
    return jsonify({
        'message': 'Logged in successfully',
        'username': username,
        'session_id': session.sid
    })


@app.route('/profile')
def profile():
    if not session.get('logged_in'):
        return jsonify({'error': 'Not logged in'}), 401
    
    return jsonify({
        'username': session.get('username'),
        'user_id': session.get('user_id'),
        'session_id': session.sid
    })


@app.route('/logout', methods=['POST'])
def logout():
    session.clear()
    return jsonify({'message': 'Logged out successfully'})


@app.route('/user/<int:user_id>')
def get_user(user_id):
    user = get_user_from_db(user_id)
    return jsonify(user)


@app.route('/products')
def get_products():
    category = request.args.get('category')
    limit = int(request.args.get('limit', 10))
    
    products = get_products_from_db(category=category, limit=limit)
    return jsonify(products)


@app.route('/cache/stats')
def cache_stats():
    db_size = redis_cache_client.dbsize()
    info = redis_cache_client.info('stats')
    
    return jsonify({
        'cached_keys': db_size,
        'keyspace_hits': info.get('keyspace_hits', 0),
        'keyspace_misses': info.get('keyspace_misses', 0),
        'hit_rate': f"{(info.get('keyspace_hits', 0) / max(info.get('keyspace_hits', 0) + info.get('keyspace_misses', 1), 1) * 100):.2f}%"
    })


@app.route('/cache/clear', methods=['POST'])
def clear_cache():
    data = request.get_json() or {}
    key_prefix = data.get('prefix', 'query')
    pattern = data.get('pattern')
    
    invalidate_cache(key_prefix=key_prefix, pattern=pattern)
    
    return jsonify({
        'message': 'Cache cleared',
        'prefix': key_prefix,
        'pattern': pattern
    })


@app.route('/session/info')
def session_info():
    all_sessions = []
    for key in redis_client.scan_iter("session:*"):
        session_data = redis_client.get(key)
        if session_data:
            try:
                data = pickle.loads(session_data)
                all_sessions.append({
                    'sid': key.decode().replace('session:', ''),
                    'data': str(data)
                })
            except:
                pass
    
    return jsonify({
        'current_session': dict(session) if session else None,
        'total_sessions': len(all_sessions),
        'all_sessions': all_sessions
    })


